INSERT INTO "public"."propositions" ("id", "proposition_id", "proposition_text", "search_queries", "is_archived") VALUES
	(2, 'marcos_robredo_2028', 'Bongbong Marcos and Leni Robredo will team up for the 2028 Philippine Presidential Election', '{"BBM Leni Robredo","Marcos endorsement Kakampink","UniTeam split Robredo"}', false),
	(3, 'sarah_duterte_wins_2028', 'Sara Duterte will win the 2028 Philippine Presidential Election', '{"Sara Duterte 2028","Sara Duterte presidential bid","Sara Duterte election plans"}', false),
	(1, 'demo-prop', 'This is a demo proposition for testing purposes.', '{"demo proposition","test proposition"}', true),
	(4, 'duterte_guilty_icc', 'Rodrigo Duterte is guilty of crimes against humanity as defined by the International Criminal Court.', '{"Duterte ICC case"}', false);
INSERT INTO "public"."sentiments" ("id", "proposition_id", "consensus_value", "attention_value", "rationale_consensus", "rationale_attention", "data_quality", "date_generated", "movement_analysis") OVERRIDING SYSTEM VALUE VALUES
	(1, 'demo-prop', 0.8, 0.6, 'The proposition has received moderate attention.', 'demo movement analysis', 0.9, '2024-06-01', 'The proposition is generally agreed upon.'),
	(2, 'marcos_robredo_2028', 0.28, 0.45, 'Both Marcos and Robredo explicitly denied discussing any 2028 alliance or political tandem, framing the meeting as non-political flood mitigation efforts, with media speculation from analysts met by skepticism and mockery from some partisan users rather than broad agreement.', 'The event prompted coverage from major outlets like Inquirer, Philstar, Bloomberg, and Business Mirror, alongside X posts from news accounts with thousands of views and dozens of engagements, making it a recognized political talking point today.', 0.85, '2026-02-22', 'Attention increased moderately from yesterday''s low chatter due to the high-profile Marcos-Robredo meeting in Naga City on flood projects, sparking speculation; consensus dipped slightly from polarization as official denials emphasized ''service first before politics,'' outweighing speculative support.'),
	(3, 'sarah_duterte_wins_2028', 0.5, 0.65, 'Duterte loyalists express strong belief in her victory, sharing articles on her achievements and declaring ''Sara for the win''; however, analysts describe her as ''winnable but not unbeatable'' amid impeachment threats and early announcement risks, maintaining a balanced divide.', 'The announcement sparked mainstream Philippine and international news coverage (e.g., Al Jazeera, Inquirer, ABS-CBN) alongside X posts with notable engagement (hundreds of likes on pro-Sara content), making it a prominent but not dominating topic.', 1, '2026-02-22', 'Attention increased due to Vice President Sara Duterte''s recent official announcement of her 2028 presidential bid, which generated news coverage and supporter buzz; consensus remained stable at polarization levels as reactions are mixed between enthusiastic support and cautious skepticism.'),
	(4, 'marcos_robredo_2028', 0.5, 0.55, 'Neutral reporting dominated with both leaders emphasizing ''service before politics'' and denying 2028 talks, while discourse split between excited pro-Robredo speculation and skeptical or mocking responses from other camps.', 'Mainstream Philippine news (Inquirer, Philstar, etc.) and some international coverage (Bloomberg) highlighted the Naga meeting, with X posts and videos gaining thousands of views and likes, marking it as a moderate talking point.', 1, '2026-02-22', 'Attention rose moderately from low levels due to President Marcos'' visit to Naga City and meeting with Mayor Leni Robredo, which fueled 2028 alliance speculation across news and social media; consensus stayed polarized as official denials balanced hopeful rumors.'),
	(5, 'sarah_duterte_wins_2028', 0.5, 0.75, 'Public discourse is deeply polarized with enthusiastic endorsements from Duterte loyalists, PDP-Laban support, and opinion pieces hailing her readiness, countered equally by administration downplaying, impeachment pushes, corruption accusations, and warnings of political jinxes or dynasty risks.', 'The topic dominates recent X posts and major news outlets like Inquirer, Manila Times, and Tribune with politician reactions, supporter rallies, and critic responses, indicating high virality post-announcement.', 0.9, '2026-02-22', 'Attention surged dramatically due to Sara Duterte''s official announcement of her 2028 presidential bid on February 18, 2026, sparking widespread reactions, while consensus held steady at polarization amid balanced pro and anti sentiments.'),
	(6, 'marcos_robredo_2028', 0.25, 0.75, 'Discourse overwhelmingly features Palace and opposition statements dismissing any political alliance or team-up for 2028, labeling it as non-political service visit; a tiny minority of users speculate or wish for Leni-Marcos tandem to counter Sara Duterte, but it''s heavily contextualized as unlikely.', 'Topic generated significant mainstream news coverage from Philstar, Inquirer, GMA, and ABS-CBN with thousands of views on X posts, plus viral chatter on the meeting, pink symbolism, and election rumors.', 0.9, '2026-02-19', 'Attention surged due to President Marcos'' high-profile visit to Naga City and meeting with Mayor Leni Robredo yesterday, fueling 2028 speculation; consensus decreased as official denials and opposition rejections dominated over fringe tandem suggestions.'),
	(7, 'sarah_duterte_wins_2028', 0.5, 0.1, 'Public opinion remains perfectly polarized, with Duterte loyalists seeing her as an early frontrunner amid her recent bid announcement, countered by strong opposition highlighting impeachment threats, budget scandals, and political rifts.', 'Extremely low chatter on X with zero recent posts retrieved since February 21 despite targeted searches, though some news coverage persists on her running mate recruitment.', 0.6, '2026-02-19', 'Scores did not move compared to yesterday due to lack of significant new discourse or viral activity, with only minor news on her running mate failing to generate buzz.'),
	(8, 'marcos_robredo_2028', 0.25, 0.75, 'Rumors of a Marcos endorsement for Robredo circulate due to the Naga meeting for flood projects, but Malacañang deems it ''untimely'' and Marcos prioritizes service over politics; X posts reflect partisan skepticism, past election grievances, and mockery rather than broad acceptance of a team-up.', 'High virality evidenced by multiple recent mainstream news articles (ABS-CBN, GMA, Inquirer) and political X discussions on the Naga visit fueling 2028 speculation, though individual post engagements are moderate.', 0.8, '2026-02-20', 'Scores remained stable as today''s data shows continued speculation from Marcos'' recent Naga visit meeting Leni Robredo, but no major shift in sentiment or volume surge beyond yesterday''s levels.'),
	(9, 'sarah_duterte_wins_2028', 0.6, 0.75, 'Supporters express strong confidence in her victory based on high SWS satisfaction ratings (+28 net, highest among officials) and regional strongholds, while opposition highlights challenges in expanding to Luzon and developing policy platforms, yielding broad but not unanimous support.', 'Extensive mainstream and international media coverage (BBC, Al Jazeera, AP, Inquirer) plus X posts with thousands of views and hashtags like #SaraDuterte2028 demonstrate high virality across platforms.', 0.9, '2026-02-20', 'Attention surged dramatically from low chatter yesterday due to the fresh wave of news coverage on Sara Duterte''s 2028 presidential announcement, while consensus edged slightly higher from perfect polarization as pro-Duterte enthusiasm citing polls outweighed critiques.'),
	(10, 'marcos_robredo_2028', 0.3, 0.75, 'Discourse dominated by Malacañang and Marcos denials framing the meeting as non-political service work, with partisan opposition from DDS and hardcore Kakampinks; a minority of analysts and excited users defend potential tandem as strong vs. Sara, but no broad acceptance it''s happening.', 'High virality evidenced by coverage across major outlets like Philstar, ABS-CBN, GMA, and X posts from influencers like Jervis Manahan and Richard Heydarian garnering 100s of likes and 10k+ views.', 0.9, '2026-02-21', 'Consensus slightly increased from 0.25 due to speculative support from analysts and some netizens post-Naga meeting, but remains low amid strong official denials; attention stable at 0.75 as media coverage and social buzz persist.'),
	(11, 'sarah_duterte_wins_2028', 0.68, 0.85, 'Pro-Sara narratives dominate with mentions of her highest SWS satisfaction rating (+28, up 6 pts) and early poll leads, portraying 2028 as inevitable; opposition highlights strategic flaws like weak Luzon appeal and impeachment risks, but with lower engagement.', 'High virality evidenced by international news coverage (BBC, Reuters, Al Jazeera), local outlets (Manila Times, Philstar), and X posts with up to 6,300 views, 253 likes, amid her bid announcement.', 0.9, '2026-02-21', 'Both scores ticked up slightly from yesterday due to sustained buzz from Sara Duterte''s recent presidential bid announcement, positive poll references, and media coverage.'),
	(12, 'marcos_robredo_2028', 0.45, 0.35, 'Official statements from Malacañang and Marcos dismiss rumors of political alliance or endorsement as ''untimely'' or non-political, with only minority analyst speculation suggesting potential viability; overall neutral reporting with skepticism prevails over agreement.', 'Multiple mainstream Philippine news outlets (ABS-CBN, Inquirer, GMA, Sunstar) reported on the Naga meeting and rumors today, but no significant X/Twitter discussion found despite searches.', 0.7, '2026-01-15', 'Attention increased moderately due to recent news coverage of President Marcos'' visit to Naga City and meeting with Leni Robredo, sparking 2028 alliance rumors, while consensus dipped slightly amid official denials.'),
	(13, 'sarah_duterte_wins_2028', 0.7, 0.75, 'Recent polls (e.g., WR Numero with 33.3% support, leading by 16 points in others) position her as the frontrunner, indicating broad public support for her potential victory, though opposition persists amid impeachment efforts and criticisms of her early bid.', 'The topic dominates headlines with coverage from BBC, Al Jazeera, Reuters, and local outlets like Inquirer and ABS-CBN following her bid announcement four days ago, signaling high virality.', 0.8, '2026-01-15', 'Attention surged dramatically due to Sara Duterte''s recent announcement of her 2028 presidential bid, covered widely by international and local media; consensus increased modestly as polls show her leading voter preferences.'),
	(14, 'marcos_robredo_2028', 0.25, 0.5, 'News reports highlight denials from the Marcos camp calling an endorsement ''untimely'' and Marcos dismissing rumors of courting Robredo, with Robredo emphasizing service over politics; no observed public support or enthusiasm for the unlikely team-up given their 2022 rivalry.', 'Multiple major Philippine news outlets like Inquirer, GMA, ABS-CBN, and PhilStar ran stories in the last 1-3 days on Marcos'' Naga visit sparking 2028 speculation, indicating a recognized talking point though social media volume was undetectable.', 0.6, '2026-01-16', 'Attention increased due to recent news coverage of President Marcos'' visit to Naga City amid 2028 team-up rumors, while consensus decreased as officials from both sides firmly dismissed any political alliance.'),
	(15, 'sarah_duterte_wins_2028', 0.75, 0.8, 'Recent polls like Tangere survey show Sara Duterte leading with 43% voter preference far ahead of others, indicating broad public support for her as a likely winner despite vocal criticism from Marcos administration allies and impeachment issues.', 'High volume of recent articles from major outlets like Inquirer, ABS-CBN, BBC, and Al Jazeera on her presidential bid announcement, running mate hints, and political reactions demonstrate sustained high virality across news platforms.', 0.9, '2026-01-16', 'Scores remained largely stable compared to yesterday, with attention slightly increasing due to fresh coverage of Sara Duterte''s running mate recruitment amid sustained post-announcement buzz, while consensus held steady supported by recent polls confirming her frontrunner status.'),
	(16, 'marcos_robredo_2028', 0.25, 0, 'No evidence of current agreement or disagreement; searches returned no relevant discussions supporting or refuting the BBM-Leni team-up, enforcing default to yesterday''s strong opposition score per low attention rule.', 'Multiple X keyword and semantic searches plus web searches yielded zero recent (since Feb 2026) results specifically on the proposition, confirming complete lack of discourse.', 0.1, '2026-01-17', 'Attention drastically decreased from moderate levels yesterday to utter silence today with no recent posts or news found; consensus defaulted to yesterday''s value due to low attention.'),
	(17, 'sarah_duterte_wins_2028', 0.75, 0.85, 'Duterte supporters on X hail her as ''future President'' with images of crowds and positive events, and one post notes her leading 2028 polls; opposition cites impeachment efforts, Marcos feud, and pro-China allegations, reflecting broad support tempered by vocal minority dissent.', 'Extensive mainstream coverage from BBC, Al Jazeera, NHK, Inquirer, and ABS-CBN on her 2028 bid announcement, feud, and running mate tease, coupled with recent X posts on her activities and political drama.', 0.9, '2026-01-17', 'Attention increased slightly due to fresh news on Sara Duterte''s recruited running mate amid ongoing post-announcement buzz, while consensus held steady with balanced pro-Duterte enthusiasm and opposition criticism similar to yesterday.'),
	(18, 'marcos_robredo_2028', 0.25, 0.25, 'Reports highlight rumors of potential team-up or endorsement triggered by President Marcos'' visit to Leni Robredo''s Naga City, but Malacañang and Marcos himself dismissed it as non-political service delivery, with no observed public endorsement or agreement.', 'Topic received coverage in major Philippine news outlets like ABS-CBN, Inquirer, GMA, and SunStar within the last 1-2 days, but searches yielded no relevant X/Twitter posts indicating low social media volume.', 0.5, '2026-01-18', 'Attention increased slightly due to recent news coverage of Marcos'' visit to Naga City sparking brief 2028 alliance rumors, while consensus remained unchanged amid official denials.'),
	(19, 'sarah_duterte_wins_2028', 0.78, 0.9, 'Recent Tangere poll (Feb 19-20, 2026) shows Sara Duterte leading with 43% support, 16 points ahead of closest rival, indicating broad acceptance as frontrunner despite vocal opposition from Marcos allies amid their feud.', 'High volume of mainstream news coverage (BBC, Al Jazeera, AP, Inquirer, ABS-CBN) on her 2028 bid announcement four days ago, plus fresh poll results dominating political discourse.', 0.85, '2026-01-18', 'Attention increased due to Sara Duterte''s recent presidential bid announcement and new polls confirming her lead, while consensus remained stable around broad support levels from yesterday.'),
	(20, 'marcos_robredo_2028', 0.25, 0.35, 'Speculation about a Marcos endorsement for Robredo exists in news reports following the Naga visit, but Palace deems it ''untimely'' and Marcos insists it''s non-political; past 2022 rivalry suggests strong public skepticism or opposition to any team-up.', 'Multiple mainstream Philippine news outlets (GMA, ABS-CBN, Philstar, Inquirer) published articles in the last 1-3 days on the rumors, indicating moderate discussion, though no significant X/Twitter volume was retrieved.', 0.7, '2026-01-19', 'Attention slightly increased due to recent news coverage of President Marcos'' Naga City visit to Leni Robredo''s turf sparking endorsement rumors, while consensus remained stable amid official denials.'),
	(21, 'sarah_duterte_wins_2028', 0.75, 0.85, 'Sara Duterte''s recent presidential bid announcement positions her as a frontrunner in media reports, supported by her political legacy, but countered by vocal social media opposition citing corruption scandals like DPWH leaks and fears of releasing scam convicts if she wins.', 'Extensive mainstream and international news coverage (BBC, Al Jazeera, ABS-CBN, Inquirer) in the past 4 days, including updates as recent as 20 hours ago, signals high virality and national discussion.', 0.8, '2026-01-19', 'Attention slightly decreased from yesterday''s peak as the initial buzz around Sara Duterte''s Feb 18 announcement settles, while consensus held steady without major shifts in sentiment.'),
	(22, 'marcos_robredo_2028', 0.25, 0.3, 'Recent news reports rumors of a Marcos-Robredo alliance for 2028 due to their Feb 21 meeting, but Marcos dismissed any courting, and there''s no broad public agreement or enthusiasm—only isolated analyst speculation amid ongoing political rivalries.', 'Low chatter on X with no recent posts matching queries since Feb 21; attention limited to a handful of news articles on the Naga meeting and dismissed 2028 rumors.', 0.6, '2026-01-20', 'Scores remained largely stable compared to yesterday, with a slight dip in attention as X discourse was minimal despite recent news on a Marcos-Robredo meeting sparking minor 2028 rumors.'),
	(23, 'sarah_duterte_wins_2028', 0.78, 0.95, 'Recent polls such as Tangere (43% preference), Manila Times (16 points ahead of Leni Robredo), and ongoing WR Numero surveys show Sara Duterte consistently leading by wide margins, indicating broad support for her winning the 2028 election despite vocal anti-Duterte sentiment from activists on X.', 'The proposition is at national dominance level with extensive mainstream and international coverage (BBC, Al Jazeera, Diplomat) of her candidacy declaration, running mate recruitment, and new polls, making it the central political topic.', 0.9, '2026-01-20', 'Attention increased from 0.85 to 0.95 due to Sara Duterte''s official presidential bid announcement four days ago and fresh poll releases today confirming her lead, while consensus slightly rose from 0.75 reflecting poll consistency without major shifts.'),
	(24, 'marcos_robredo_2028', 0.25, 0.4, 'Discourse centers on Marcos'' Naga visit to Leni Robredo for flood relief, with Palace and Marcos insisting ''no politics'' and dismissing 2028 alliance rumors as untimely; a few analysts speculate on possible endorsement but no broad agreement or enthusiasm for the proposition.', 'Major Philippine news outlets like Inquirer, GMA, and ABS-CBN published articles today on the meeting and speculation, indicating moderate discussion, though X searches yielded no recent matching posts.', 0.7, '2026-01-21', 'Attention slightly increased due to recent Marcos-Robredo meeting in Naga sparking 2028 speculation in news, while consensus remained stable amid official denials.'),
	(25, 'sarah_duterte_wins_2028', 0.82, 0.97, 'Recent Tangere survey places Sara Duterte at 43% voter preference, leading early 2028 polls, signaling broad support from her loyal base despite vocal anti-Duterte sentiment on X and ongoing plunder complaints.', 'High volume of recent coverage from major outlets like BBC, Al Jazeera, AP, and local news on her presidential bid announcement, polls, and feud with Marcos.', 0.9, '2026-01-21', 'Consensus edged up slightly with new polls reaffirming her lead as frontrunner, while attention stayed near peak levels due to sustained media coverage of her announcement and related developments.'),
	(26, 'marcos_robredo_2028', 0.25, 0.25, 'Official statements from Marcos and Robredo explicitly deny any political discussions or 2028 alliance plans during their recent Naga meeting, with opposition figures opposing the idea and only isolated analyst speculation in favor; public discourse treats it as untimely rumor given historical rivalry.', 'Topic appears in several mainstream Philippine news outlets due to President Marcos'' February 21 visit to Naga City sparking brief 2028 team-up rumors, but no matching recent X posts found indicating minimal social media volume.', 0.6, '2026-01-22', 'Attention decreased from moderate-low to low chatter as social media shows no recent posts despite news coverage of Marcos'' Naga visit; consensus remained stable amid official denials reinforcing skepticism.'),
	(27, 'sarah_duterte_wins_2028', 0.85, 0.9, 'Recent opinion polls from sources like Manila Times and others position Sara Duterte as the frontrunner for 2028, with significant leads, reflecting broad acceptance of her viability despite vocal opposition and scandals.', 'The topic dominates headlines with her Feb 18 presidential bid announcement covered by BBC, Al Jazeera, AP, and local outlets like Inquirer and ABS-CBN, plus new poll releases ensuring high virality.', 0.9, '2026-01-22', 'Consensus slightly increased due to new polls confirming Sara Duterte''s lead in early 2028 surveys, while attention dipped marginally from peak post-announcement but remains high amid ongoing media coverage.'),
	(28, 'marcos_robredo_2028', 0.25, 0, 'Absence of any supportive, neutral, or even speculative mentions of a BBM-Leni team-up; searches returned unrelated opposition unity talks (e.g., Leni-Kiko reunion) or none at all, justifying continuation of strong opposition.', 'No X posts or web results discussing the proposition or related queries on February 22, 2026, despite BBM''s recent visit to Leni''s city.', 0.2, '2026-01-23', 'No change in consensus due to low attention defaulting to yesterday''s score; attention dropped from low chatter to complete silence with no mentions of the proposition today.'),
	(29, 'sarah_duterte_wins_2028', 0.85, 0.85, 'Recent polls like Tangere (43% preference post-announcement) and Manila Times (16-point lead over rivals) indicate broad support and positioning as the favorite to win 2028, despite some past opposition and impeachment talks.', 'High volume of mainstream news coverage (BBC, Al Jazeera, Inquirer, ABS-CBN within last 24 hours) and new polls confirm significant virality and discussion around her bid.', 0.9, '2026-01-23', 'Scores remained stable compared to yesterday as Sara Duterte''s recent presidential bid announcement and leading poll results sustain high public interest and perceived frontrunner status without major shifts.'),
	(30, 'marcos_robredo_2028', 0.25, 0.25, 'Speculation arose from Marcos'' Naga visit and interaction with Robredo, but Palace called endorsement ''untimely,'' Marcos stressed service over politics, and no evidence of public buy-in given their 2022 rivalry; only niche speculation without support.', 'Several recent news articles from ABS-CBN, Inquirer, and GMA discuss the rumors tied to the Naga event, but X searches yielded no relevant posts, suggesting low social media chatter.', 0.5, '2026-01-24', 'Attention increased slightly from 0.0 due to President Marcos'' recent visit to Naga City sparking media speculation about a 2028 tandem, while consensus held steady at strong opposition as rumors were promptly dismissed.'),
	(31, 'sarah_duterte_wins_2028', 0.82, 0.9, 'Recent Tangere poll (Feb 19-20, 2026) shows Sara Duterte leading with 43% voter preference, indicating broad support as frontrunner, though opposition figures like Trillanes urge unity to defeat her and highlight accountability issues.', 'Her Feb 18 announcement of presidential bid received extensive coverage from international outlets like BBC, Al Jazeera, AP, and local news, dominating political discourse with poll discussions.', 0.85, '2026-01-24', 'Consensus slightly decreased from 0.85 due to increased opposition calls to unite against her amid impeachment threats, while attention increased slightly from 0.85 boosted by her recent presidential bid announcement.'),
	(32, 'marcos_robredo_2028', 0.25, 0.35, 'Leaders from both sides, including Marcos and Robredo, explicitly denied any political discussions or 2028 team-up during their meeting, calling rumors untimely or a disservice to public service; limited speculation from analysts represents a tiny minority.', 'Several mainstream news articles (ABS-CBN, Inquirer, GMA, SunStar) covered the rumors post-Naga visit, but searches yielded no recent viral X posts, indicating low social media volume.', 0.7, '2026-01-25', 'Attention slightly increased due to recent Naga City meeting between Marcos and Robredo sparking rumor coverage in news media, while consensus stable amid firm denials from officials.'),
	(33, 'sarah_duterte_wins_2028', 0.85, 0.95, 'Sara Duterte leads early 2028 presidential polls with 43% voter preference in recent Tangere survey and dominates pre-election surveys per Wikipedia, reflecting broad agreement on her frontrunner status despite opposition calls to unite against her.', 'Major news coverage from BBC, Al Jazeera, AP News, Inquirer, and others on her presidential run announcement 4 days ago and hints at a running mate indicate high virality and national political focus.', 0.9, '2026-01-25', 'Consensus slightly increased and attention remained high following VP Sara Duterte''s announcement of her 2028 presidential bid and new polls affirming her lead, sustaining yesterday''s strong sentiment.'),
	(34, 'marcos_robredo_2028', 0.25, 0.25, 'Official Palace and Marcos statements dismiss endorsement or alliance rumors as ''untimely'' or apolitical, reflecting strong opposition to the proposition amid historical 2022 rivalry; only niche analysts speculate on potential benefits like Robredo beating Duterte with Marcos backing.', 'Low chatter limited to a handful of recent news articles on the Naga visit sparking 2028 rumors, with no significant or viral discussion found on X/Twitter.', 0.6, '2026-01-26', 'Scores stable compared to yesterday; brief news speculation from Marcos''s recent Naga visit did not gain traction on social media or lead to broader public discourse.'),
	(35, 'sarah_duterte_wins_2028', 0.85, 0.85, 'Sara Duterte consistently leads in the latest available polls (e.g., 31.4% in WR Numero Aug 2025), with opposition leaders calling for unity to rival her and media questioning if she is unbeatable, indicating broad acceptance of her as the likely winner despite impeachment threats and political feuds.', 'High volume of recent mainstream news coverage from BBC, Al Jazeera, Inquirer, and ABS-CBN on her 2028 bid and running mate recruitment, combined with active political discussions on X reflecting the feud with Marcos.', 0.9, '2026-01-26', 'Scores remained largely stable compared to yesterday, with attention slightly decreasing as the initial buzz from Sara Duterte''s presidential bid announcement four days ago normalizes, while consensus holds firm due to her established frontrunner status.'),
	(36, 'marcos_robredo_2028', 0.25, 0.25, 'Official statements deny any political intent behind the recent Naga meeting between Marcos and Robredo, dismissing 2028 alliance rumors; no evidence of public support or acceptance of a team-up, consistent with strong opposition.', 'Coverage limited to a handful of news articles on yesterday''s work-related meeting, with zero relevant discussions found on X despite targeted searches.', 0.4, '2026-01-27', 'Scores remained stagnant as recent news of a Marcos-Robredo meeting was explicitly clarified as non-political, mirroring yesterday''s low agreement and chatter without new developments sparking change.'),
	(37, 'sarah_duterte_wins_2028', 0.9, 0.95, 'Early polls post-announcement (Tangere Feb 19-20: 43%; Manila Times: 16-pt lead) position Sara Duterte as the clear frontrunner, reflecting broad support amid her feud with Marcos, though vocal opposition labels her pro-China.', 'The topic dominates with international news coverage (BBC, Al Jazeera), Wikipedia updates, recent polls, and polarized X discussions, marking high virality following her bid declaration.', 0.9, '2026-01-27', 'Scores increased slightly due to Sara Duterte''s recent presidential bid announcement on Feb 18 and new polls confirming her strong lead, boosting both agreement on her frontrunner status and discussion volume.'),
	(38, 'marcos_robredo_2028', 0.25, 0.3, 'The proposition faces strong skepticism as Malacañang labels alliance talks ''untimely'' and non-political, with Robredo avoiding confirmation; only niche speculation from analysts and fans exists without broad support.', 'Low-to-moderate volume with several recent news articles from ABS-CBN, Rappler, and Inquirer on the Marcos-Robredo meeting and pink socks anecdote, but negligible relevant discussions on X/Twitter.', 0.6, '2026-01-28', 'Attention saw a slight increase from yesterday due to news coverage of President Marcos'' visit to Naga City Mayor Leni Robredo, sparking brief speculation, while consensus stayed stable amid official dismissals of any political alliance.'),
	(39, 'sarah_duterte_wins_2028', 0.88, 0.9, 'Recent Tangere survey shows Sara Duterte leading 2028 presidential preferences at 43%, with Wikipedia noting she dominates early polls alongside Bong Go; despite Marcos feud and impeachment threats, no strong rejection observed, indicating broad support from her base.', 'High volume of recent news coverage from BBC, Al Jazeera, Inquirer, ABS-CBN, and others on her announcement, running mate recruitment, and polls, maintaining significant political discourse.', 0.9, '2026-01-28', 'Scores remained largely stable compared to yesterday, with consensus holding strong due to confirming polls and attention slightly dipping as the announcement hype from 4 days ago begins to normalize.'),
	(40, 'marcos_robredo_2028', 0.25, 0, 'No current discourse on the proposition found across X or web searches, resulting in default to yesterday''s consensus score of 0.25 amid negligible attention.', 'Utter silence with zero relevant posts on X (including latest and semantic searches) and no pertinent news or mentions in web results for recent dates.', 0.1, '2026-01-29', 'Attention dropped to zero due to complete absence of any mentions or discussions today; consensus held steady at yesterday''s level per low-attention default rule.'),
	(41, 'sarah_duterte_wins_2028', 0.86, 0.85, 'Sara Duterte leads early pre-election polls and is seen as a strong frontrunner by lawmakers and analysts, with broad acceptance of her winnability despite vocal opposition from Marcos allies and questions on her strategy.', 'High volume of recent news coverage across major Philippine outlets (Inquirer, ABS-CBN) and international media (BBC, Al Jazeera) on her 2028 bid announcement and running mate recruitment, though limited recent X discourse.', 0.9, '2026-01-29', 'Scores slightly decreased from yesterday due to emerging criticisms of her early bid timing and impeachment shadows, but remained high amid ongoing media buzz without major new events.'),
	(42, 'marcos_robredo_2028', 0.25, 0.25, 'All retrieved news sources report the Marcos-Robredo meeting as strictly for flood response and public service, with both parties denying any political agenda or 2028 election talks; no sources or social posts endorse or seriously entertain the proposition of them teaming up.', 'Topic received low-moderate mainstream news coverage around the recent Naga visit but no detectable volume on X/Twitter despite multiple searches.', 0.6, '2026-01-30', 'Attention increased slightly due to news coverage of President Marcos'' visit to Naga City Mayor Leni Robredo on Feb 21, but consensus remained stable as the meeting was explicitly described as non-political with no team-up discussions.'),
	(43, 'sarah_duterte_wins_2028', 0.87, 0.95, 'Discourse highlights her massive 32 million votes from 2022 haunting rivals, endorsements from groups like 1Bangsa, and neutral response from PBBM, indicating broad support and acceptance as a strong contender despite vocal opposition alarms over timing and controversies.', 'The announcement dominated recent news cycles with multiple articles from PNA, Business Mirror, Tribune, and others published in the last 3 days, alongside X discussions tying it to impeachment clearance, marking high virality.', 0.9, '2026-01-30', 'Attention surged due to Vice President Sara Duterte''s recent official announcement of her 2028 presidential bid, while consensus saw a minor increase as it reinforces her frontrunner status amid supportive narratives.'),
	(44, 'marcos_robredo_2028', 0.25, 0.4, 'Leaders Marcos and Robredo explicitly dismissed political discussions during the Naga visit, calling rumors of a 2028 alliance premature and focusing on flood control; while one analyst speculated a Marcos-endorsed Robredo could defeat rivals, this represents only a tiny, unendorsed minority view against widespread neutral-to-skeptical reporting.', 'Multiple mainstream Philippine news sources (GMA, Inquirer, Sunstar) published stories today on the Naga visit and 2028 speculation, indicating moderate discussion as a recognized talking point, though no significant X/Twitter chatter was found.', 0.7, '2026-01-31', 'Attention increased moderately due to President Marcos''s recent visit to Naga City—where Leni Robredo is mayor—sparking rumors of a 2028 team-up in mainstream news outlets; consensus remained stable amid firm denials from both leaders emphasizing service over politics.'),
